import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"简易长矛组装术","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/简易长矛组装术.md","filePath":"4.资源分区/6.技艺及称号/杂项/简易长矛组装术.md"}'),o={name:"4.资源分区/6.技艺及称号/杂项/简易长矛组装术.md"};function d(_,a,l,i,b,c){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"简易长矛组装术",tabindex:"-1"},[n("简易长矛组装术 "),e("a",{class:"header-anchor",href:"#简易长矛组装术","aria-label":'Permalink to "简易长矛组装术"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),s('<h1 id="简易长矛组装术-1" tabindex="-1">简易长矛组装术 <a class="header-anchor" href="#简易长矛组装术-1" aria-label="Permalink to &quot;简易长矛组装术&quot;">​</a></h1><p>【蕾忍派秘传·简易长矛组装·术】技艺</p><p>C+1000<br> 当你想要消灭碍眼的敌人的时候，再也不用因为手里的武器长度不够而痛苦了<br> 来自绝密监狱岛的传奇技艺——【蕾忍派秘传·简易长矛组装·术】，将会让你摆脱这一困境<br> 下面就让我告诉你如何制造这一神器：</p><p>第一步，找一个你要握持的主武器（必须是近战冷兵器，不然你为什么要提高射程呢？）<br> 第二步，找到绳子、胶布、胶水、发带、订书机等其他任何可以用于固定的东西<br> 第三步，拿起你周围的另一备用武器（同样是近战冷兵器），把它们绑在一起</p><p>你需要以一个自由动作来进行以上组装，组装后持续一个场景，以此方法组装后的武器名称将会变成【简易长矛】，这意味着如果有涉及武器真名之类的效果将会失效<br> 【简易长矛】在你握持的主武器基础上，额外拥有你添加的另一备用武器的【一半武器伤害】与【所有特性】，且触及范围提升3米<br> 此外，【简易长矛】还可以满足【长柄】、【双手】、【临时武器】的要求，额外具有【破甲5】，但是使用它的专业仍为主武器对应的专业，并且无论如何必须用双手持用</p><p>【简易版·简易长矛组装·术】技艺</p><p>D+500<br> 有人反应原版的技艺太过深奥，把武器一个个绑起来的手法还是太吃操作了<br> 主神，主神，有没有更简单更轮椅的提升冷兵器射程的技艺呢<br> 有的，兄弟，有的，这里是【简易版·简易长矛组装·术】</p><p>该版本的操作方法和原版一致，但是组装后的【简易版简易长矛】的效果改为【武器伤害】提升3L，触及范围提升1m<br> 并且因为太过简易，可以单手持用了<br> 此外，如果使用时太用力，可能会散架，所以也没有了额外的【破甲5】</p><p>该技艺无法与【蕾忍派秘传·简易长矛组装·术】共存，但是可以差价升级为【蕾忍派秘传·简易长矛组装·术】</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
